 17→function buildChordAttachments(run, spacing, startOffset, endOffset, side) {
 18→  if (!(run?.points || []).length || spacing <= EPSILON) return [];
 19→
 20→  const chordLength = getTopChordRunLength(run);
 21→  const limit = chordLength - Math.max(endOffset, 0);
 22→  if (limit < Math.max(startOffset, 0) - EPSILON) return [];
 23→
 24→  const attachments = [];
 25→  for (let distanceAlong = Math.max(startOffset, 0), index = 0; distanceAlong <= limit + EPSILON; distanceAlong += spacing, index += 1) {
 26→    const sample = sampleTopChordRun(run, distanceAlong);
 27→    if (!sample) continue;
 28→
 29→    attachments.push({
 30→      id: `${side}_${index}`,
 31→      side,
 32→      localPoint: sample.point,
 33→      tangent: sample.tangent,
 34→      distanceAlong: sample.distanceAlong,
 35→    });
 36→  }
 37→
 38→  return attachments;
 39→}
