 50→export function buildTrussPurlinAttachments(profile, purlinSystem = {}) {
 51→  if (!purlinSystem?.enabled) return [];
 52→
 53→  const spacing = Math.max(Number(purlinSystem.spacing || 0), 0);
 54→  const startOffset = Math.max(Number(purlinSystem.startOffset || 0), 0);
 55→  const endOffset = Math.max(Number(purlinSystem.endOffset || 0), 0);
 56→  if (spacing <= EPSILON) return [];
 57→
 58→  const topChordRuns = (profile?.topChordRuns || [])
 59→    .filter((run) => (run.points || []).length >= 2);
 60→
 61→  if (!topChordRuns.length) {
 62→    return buildChordAttachments(
 63→      {
 64→        id: 'main',
 65→        side: 'main',
 66→        points: profile?.roofOutline || [],
 67→      },
 68→      spacing,
 69→      startOffset,
 70→      endOffset,
 71→      'main'
 72→    );
 73→  }
 74→
 75→  return dedupeAttachments(topChordRuns.flatMap((run, index) => (
 76→    buildChordAttachments(
 77→      run,
 78→      spacing,
 79→      startOffset,
 80→      endOffset,
 81→      run.side || run.id || `run_${index + 1}`
 82→    )
 83→  )));
 84→}
