 86→export function createDetailPurlinMarker(attachment, markerLength = DETAIL_MARKER_LENGTH) {
 87→  if (!attachment?.localPoint) return null;
 88→
 89→  const tangent = normalize2d(attachment.tangent || { x: 1, z: 0 });
 90→  const normal = { x: -tangent.z, z: tangent.x };
 91→  const halfLength = markerLength / 2;
 92→
 93→  return {
 94→    id: attachment.id,
 95→    start: {
 96→      x: attachment.localPoint.x - (normal.x * halfLength),
 97→      z: attachment.localPoint.z - (normal.z * halfLength),
 98→    },
 99→    end: {
100→      x: attachment.localPoint.x + (normal.x * halfLength),
101→      z: attachment.localPoint.z + (normal.z * halfLength),
102→    },
103→  };
104→}
