 42→function sampleOutlineAtX(points = [], x = 0) {
 43→  if (!points.length) return { x, z: 0 };
 44→  if (points.length === 1) return { x, z: points[0].z };
 45→
 46→  const ordered = [...points].sort((a, b) => a.x - b.x);
 47→  if (x <= ordered[0].x + EPSILON) return { x, z: ordered[0].z };
 48→  if (x >= ordered[ordered.length - 1].x - EPSILON) return { x, z: ordered[ordered.length - 1].z };
 49→
 50→  for (let index = 0; index < ordered.length - 1; index += 1) {
 51→    const start = ordered[index];
 52→    const end = ordered[index + 1];
 53→    if (x < start.x - EPSILON || x > end.x + EPSILON) continue;
 54→    const span = end.x - start.x;
 55→    if (Math.abs(span) <= EPSILON) {
 56→      return { x, z: end.z };
 57→    }
 58→    const ratio = (x - start.x) / span;
 59→    return {
 60→      x,
 61→      z: lerp(start.z, end.z, ratio),
 62→    };
 63→  }
 64→
 65→  return { x, z: ordered[ordered.length - 1].z };
 66→}
